// MARK: - Analytics Tracking for Deep Links

class DeepLinkAnalytics {
    
    enum Source: String {
        case marketingCampaign = "marketing_campaign"
        case emailNotification = "email_notification"
        case pushNotification = "push_notification"
        case unknown = "unknown"
    }
    
    static func trackDeepLinkOpened(url: URL, route: DeepLinkRoute) {
        let source = extractSource(from: url)
        let campaignID = extractCampaignID(from: url)
        
        let eventParams: [String: String] = [
            "url": url.absoluteString,
            "route": routeDescription(route),
            "source": source.rawValue,
            "campaign_id": campaignID ?? "none"
        ]
        
        print("DeepLink Analytics Event: \(eventParams)")
        // Send to analytics service (Firebase, Amplitude, etc.)
    }
    
    private static func extractSource(from url: URL) -> Source {
        guard let queryItems = URLComponents(url: url, resolvingAgainstBaseURL: false)?.queryItems else {
            return .unknown
        }
        
        if let sourceParam = queryItems.first(where: { $0.name == "utm_source" })?.value {
            switch sourceParam {
            case "email": return .emailNotification
            case "campaign", "marketing": return .marketingCampaign
            case "push": return .pushNotification
            default: return .unknown
            }
        }
        
        return .unknown
    }
    
    private static func extractCampaignID(from url: URL) -> String? {
        return URLComponents(url: url, resolvingAgainstBaseURL: false)?
            .queryItems?
            .first(where: { $0.name == "utm_campaign" })?
            .value
    }
    
    private static func routeDescription(_ route: DeepLinkRoute) -> String {
        switch route {
        case .profile(let userID): return "profile_\(userID)"
        case .paymentConfirm(let txID): return "payment_confirm_\(txID ?? "none")"
        case .adminSettings: return "admin_settings"
        case .notFound: return "not_found"
        }
    }
}

// MARK: - SceneDelegate Integration

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    private lazy var deepLinkNavigator = DeepLinkNavigator(window: window)
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = scene as? UIWindowScene else { return }
        
        window = UIWindow(windowScene: windowScene)
        
        let rootVC = UIViewController()
        rootVC.view.backgroundColor = .systemBackground
        let nav = UINavigationController(rootViewController: rootVC)
        
        window?.rootViewController = nav
        window?.makeKeyAndVisible()
        
        // Handle universal link if app was launched from one
        if let userActivity = connectionOptions.userActivities.first,
           userActivity.activityType == NSUserActivityTypeBrowsingWeb,
           let url = userActivity.webpageURL {
            handleUniversalLink(url: url)
        }
    }
    
    // Called when a universal link is opened while the app is already running
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return
        }
        handleUniversalLink(url: url)
    }
    
    private func handleUniversalLink(url: URL) {
        let route = UniversalLinkParser.parse(url: url)
        
        // Track analytics
        DeepLinkAnalytics.trackDeepLinkOpened(url: url, route: route)
        
        // Navigate
        deepLinkNavigator.navigate(to: route)
    }
}

