@main
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    var window: UIWindow?
    private lazy var deepLinkNavigator = DeepLinkNavigator(window: window)
    
    func application(_ application: UIApplication,
                     didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        
        // Only set up window if not using scenes
        if #available(iOS 13.0, *) {
            // Scene delegate handles window setup
        } else {
            window = UIWindow(frame: UIScreen.main.bounds)
            let rootVC = UIViewController()
            rootVC.view.backgroundColor = .systemBackground
            let nav = UINavigationController(rootViewController: rootVC)
            window?.rootViewController = nav
            window?.makeKeyAndVisible()
        }
        
        return true
    }
    
    // Handle universal links on iOS 12 and earlier
    func application(_ application: UIApplication,
                     continue userActivity: NSUserActivity,
                     restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return false
        }
        
        let route = UniversalLinkParser.parse(url: url)
        DeepLinkAnalytics.trackDeepLinkOpened(url: url, route: route)
        deepLinkNavigator.navigate(to: route)
        
        return true
    }
    
    // MARK: UISceneSession Lifecycle
    
    @available(iOS 13.0, *)
    func application(_ application: UIApplication,
                     configurationForConnecting connectingSceneSession: UISceneSession,
                     options: UIScene.ConnectionOptions) -> UISceneConfiguration {
        return UISceneConfiguration(name: "Default Configuration", sessionRole: connectingSceneSession.role)
    }
}